  { memWalIndexDetailsSnapshotTsMillis :: {-# UNPACK #-} !Int64
  -- ^ Snapshot timestamp (Unix timestamp in milliseconds).
  , memWalIndexDetailsNumShards :: {-# UNPACK #-} !Word32
